// WF 헬스 모니터 — 주기 대비 3배 초과 시 경고
const errorExecs = $input.first().json?.data || [];
const successExecs = $('성공 실행 조회').first().json?.data || [];

const watchList = [
  { id: 'jaTfiQuY35DjgrxN', name: 'FA-001 강사등급', intervalMin: 5 },
  { id: 'ovWkhq7E0ZqvjBIZ', name: 'FA-002 강사신청알림', intervalMin: 60 },
  { id: 'Ks4JvBC06cEj6b8b', name: 'FA-003 반려이메일', intervalMin: 5 },
  { id: '7MXN1lNCR3b7VcLF', name: 'WF#1 정부지원', intervalMin: 1440 },
  { id: 'TrE9obAsBMtv5H1W', name: 'IMG-SYNC', intervalMin: 5 },
  { id: 'EPXKj5wQf5DJ45hc', name: 'S3A-001 주간리포트', intervalMin: 10080 },
  { id: '5qCeEU6FemDLyaGU', name: 'S3A-002 RFM', intervalMin: 10080 },
];

const now = Date.now();
const alerts = [];
const staleAlerts = [];

// 1) 최근 에러 체크 (1시간 이내)
const oneHourAgo = now - 60 * 60 * 1000;
for (const exec of errorExecs) {
  const finishedAt = new Date(exec.stoppedAt || exec.startedAt).getTime();
  if (finishedAt > oneHourAgo) {
    const wf = watchList.find(w => w.id === exec.workflowId);
    const wfName = wf ? wf.name : (exec.workflowData?.name || exec.workflowId);
    alerts.push(`\u274c ${wfName}: 실행 에러 (${new Date(exec.stoppedAt).toLocaleString('ko-KR', {timeZone: 'Asia/Seoul'})})`);
  }
}

// 2) 주기 대비 3배 초과 (stale) 체크
for (const wf of watchList) {
  const lastSuccess = successExecs.find(e => e.workflowId === wf.id);
  if (!lastSuccess) {
    staleAlerts.push(`\u23f0 ${wf.name}: 최근 성공 기록 없음`);
    continue;
  }
  const lastAt = new Date(lastSuccess.stoppedAt || lastSuccess.startedAt).getTime();
  const ageMin = (now - lastAt) / 60000;
  const threshold = wf.intervalMin * 3;
  if (ageMin > threshold) {
    const ageHours = Math.round(ageMin / 60);
    staleAlerts.push(`\u23f0 ${wf.name}: ${ageHours}시간 전 마지막 성공 (임계: ${Math.round(threshold / 60)}시간)`);
  }
}

const allAlerts = [...alerts, ...staleAlerts];

if (allAlerts.length === 0) {
  return [{ json: { hasIssues: false, message: '' } }];
}

const message = `\u26a0\ufe0f WF 헬스 경고\n\n${allAlerts.join('\n')}\n\n시각: ${new Date().toLocaleString('ko-KR', {timeZone: 'Asia/Seoul'})}`;

return [{ json: { hasIssues: true, message } }];
